sql:
SELECT value, label, curve_value_status
FROM curve_values
WHERE curve_value_status = 'rejected';

SELECT curve_status, COUNT(*) AS curve_count
FROM curves
GROUP BY curve_status;

SELECT COUNT(*) AS total_pending_entries
   FROM curve_values
   WHERE curve_value_status = 'pending';

SELECT valuation_date
FROM valuation_dates
WHERE valuation_date_type = 'business day' AND valuation_date_status = 'completed';

SELECT DISTINCT valuation_date
FROM valuation_dates
WHERE valuation_date_status = 'pending';

SELECT COUNT(*) as pending_valuation_dates_count
FROM valuation_dates
WHERE valuation_date_status = 'pending';

SELECT MAX(value) AS max_verified_value
FROM curve_values
WHERE curve_value_status = 'verified';

SELECT update_reason
FROM curve_updates
WHERE updated_by = 1 AND update_timestamp > '2023-04-01 12:00:00';

SELECT updated_by, COUNT(update_id) AS update_count
FROM curve_updates
GROUP BY updated_by;

SELECT COUNT(*) 
FROM curves 
WHERE curve_type = 'interest rate' AND curve_status = 'active';

external_knowledge:
- 'Most recent updates' refers to the updates with the most recent valuation timestamp; 
- 'Curve values' are the values of the interest rate curves at specific dates; 
- 'Compliant with regulatory standards' means the curve values meet certain regulatory requirements.

sql:
SELECT curve_value_id, valuation_date_id, value, label, curve_value_status
   FROM curve_values
   WHERE curve_value_id = 0;

SELECT label, COUNT(*) AS curve_value_count
FROM curve_values
GROUP BY label;

external_knowledge:
- The term 'verified' refers to the curve value status being confirmed or approved; 
- The term 'compliant' refers to the regulatory compliance status being in accordance with the rules and regulations. 
- 'Average of all verified curve values' refers to a calculated mean of all curve values with the status 'verified'.

sql:
SELECT valuation_date_type, COUNT(*) AS date_type_count
FROM valuation_dates
GROUP BY valuation_date_type;
